While there's no built-in universal parser in Python, you can create a custom solution. Here's a function that can handle parsing for various types, including nested structures:

```Plain Text
from typing import Any, List, Dict, Union, get_origin, get_args

def universal_parser(value: Any, target_type: Any) -> Any:
    origin = get_origin(target_type)
    args = get_args(target_type)

    if origin is list:
        if not isinstance(value, list):
            raise TypeError(f"Expected list, got {type(value)}")
        return [universal_parser(item, args[0]) for item in value]

    elif origin is dict:
        if not isinstance(value, dict):
            raise TypeError(f"Expected dict, got {type(value)}")
        return {universal_parser(k, args[0]): universal_parser(v, args[1]) for k, v in value.items()}

    elif origin is Union:
        for arg in args:
            try:
                return universal_parser(value, arg)
            except (ValueError, TypeError):
                continue
        raise ValueError(f"Cannot parse {value} to any of {args}")

    elif target_type in (int, float, str, bool):
        return target_type(value)

    else:
        raise ValueError(f"Unsupported type: {target_type}")

# Usage examples:
value1: List[str] = ['1', '2', '3']
parsed1 = universal_parser(value1, List[int])
print(parsed1)  # [1, 2, 3]

value2: Dict[str, str] = {'a': '1', 'b': '2'}
parsed2 = universal_parser(value2, Dict[str, int])
print(parsed2)  # {'a': 1, 'b': 2}

value3: List[str] = ['1', '2.5', 'true']
parsed3 = universal_parser(value3, List[Union[int, float, bool]])
print(parsed3)  # [1, 2.5, True]
```


