```Python
import json
import os

# File path for the JSON data
JSON_FILE = 'static/notes.json'

# Initialize empty JSON file if it doesn't exist
def init_json_file():
    if not os.path.exists(JSON_FILE):
        with open(JSON_FILE, 'w') as f:
            json.dump([], f)

# Create new record
def create(name, title):
    init_json_file()

    # Read existing data
    with open(JSON_FILE, 'r') as f:
        data = json.load(f)

    # Generate new ID (simple increment)
    new_id = len(data) + 1 if data else 1

    # Create new record
    new_record = {
        'id': new_id,
        'name': name,
        'title': title
    }

    # Append new record
    data.append(new_record)

    # Write back to file
    with open(JSON_FILE, 'w') as f:
        json.dump(data, f, indent=4)

    return new_record

# Get all data
def get_data():
    init_json_file()

    with open(JSON_FILE, 'r') as f:
        data = json.load(f)
    return data

# Get single record by ID
def get_record(record_id):
    data = get_data()
    return next((item for item in data if item['id'] == record_id), None)

# Update record
def update_record(record_id, name=None, title=None):
    data = get_data()

    for item in data:
        if item['id'] == record_id:
            if name is not None:
                item['name'] = name
            if title is not None:
                item['title'] = title

            with open(JSON_FILE, 'w') as f:
                json.dump(data, f, indent=4)
            return item

    return None

# Delete record
def delete_record(record_id):
    data = get_data()

    filtered_data = [item for item in data if item['id'] != record_id]

    if len(filtered_data) != len(data):
        with open(JSON_FILE, 'w') as f:
            json.dump(filtered_data, f, indent=4)
        return True

    return False
```


