        pass

    def __str__(self):
        return 'grandparent'

class parent(grandparent):
    def __init__(self):
        pass

    def __str__(self):
        return f'{super().__str__()},parent'

class child(parent):
    def __init__(self):
        pass

    def __str__(self):
        grandparent_str = self.__class__.__mro__[2].__str__(self)
        return f'{grandparent_str},child'

# Test the classes
