            'all_count': all_stats['all_count'],
            'all_earnings': all_stats['all_earnings'] or 0,
            'successful_count': successful_stats['successful_count'],
            'successful_earnings': successful_stats['successful_earnings'] or 0
        }


class TradesDistributionSerializer(serializers.Serializer):
    def to_representation(self, instance):
        sellers = self.trades.values('creator__username')\
            .annotate(total_earnings=Sum('trade_price'))\
            .values('creator__username', 'total_earnings')

        return {
            'sellers': {
                item['creator__username']: item['total_earnings']
                for item in sellers
            }
        }
