from pyparsing import Word, alphas, alphanums, oneOf, infixNotation, opAssoc, QuotedString

class Node:
    def __init__(self, tokens):
        self.operator = tokens[0][1]
        self.operands = tokens[0][0::2]
        self.id = None

    def __str__(self):
        return f"({self.operator} {' '.join(map(str, self.operands))})"

class LeafNode:
    def __init__(self, tokens):
        self.field = tokens[0]
        self.operator = '='
        self.value = tokens[2]
        self.id = None

    def __str__(self):
        return f"{self.field} = {self.value}"

def create_parser():
    field = Word(alphas)
    value = QuotedString("'")

    comparison = (field + '=' + value).setParseAction(LeafNode)

    expr = infixNotation(comparison,
        [
            ('OR', 2, opAssoc.LEFT, Node),
            ('AND', 2, opAssoc.LEFT, Node),
        ])

