def assign_ids(node, next_id=1):
    node.id = next_id
    next_id += 1

    if isinstance(node, Node):
        for operand in node.operands:
            if isinstance(operand, (Node, LeafNode)):
                next_id = assign_ids(operand, next_id)

    return next_id

def to_dict(root):
