import subprocess
from contextlib import contextmanager
import pytest

class AssertionCollector:
    def __init__(self):
        self.failures = []

    @contextmanager
    def collect(self):
        try:
            yield
        except AssertionError as e:
            self.failures.append(str(e))

    def assert_all(self):
        if self.failures:
            pytest.fail(f"Multiple assertions failed:\n" + "\n".join(self.failures))

def test_executable_script():
    collector = AssertionCollector()

    with collector.collect():
        result = subprocess.check_output([executable_script], encoding="UTF-8")
        assert result != "", f"Error: {result}"

    with collector.collect():
        result_2 = subprocess.check_output([another_executable_script], encoding="UTF-8")
        assert result_2 != "", f"Error: {result_2}"

    collector.assert_all()
```


11. Using a decorator approach:

```Python
import subprocess
import functools
import pytest

def collect_failures(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        failures = []

        def custom_assert(condition, message=""):
            try:
                assert condition, message
            except AssertionError as e:
                failures.append(str(e))

        # Replace assert with custom_assert in the test function
        func.__globals__['assert_check'] = custom_assert
        func(*args, **kwargs)

        if failures:
            pytest.fail(f"Multiple assertions failed:\n" + "\n".join(failures))

    return wrapper

@collect_failures
def test_executable_script():
    result = subprocess.check_output([executable_script], encoding="UTF-8")
    assert_check(result != "", f"Error: {result}")

    result_2 = subprocess.check_output([another_executable_script], encoding="UTF-8")
