Here's a solution using Django's database functions for geographical calculations. First, let's modify the model to optimize for geo-queries:

```Python
from django.db import models
from django.db.models.functions import ACos, Cos, Sin, Radians
from django.db.models import F, ExpressionWrapper, FloatField

class Provider(models.Model):
    name = models.CharField(max_length=100)
    lat = models.DecimalField(max_digits=9, decimal_places=6)  # Changed to DecimalField
    lon = models.DecimalField(max_digits=9, decimal_places=6)  # Changed to DecimalField
    address = models.TextField(null=True, blank=True)

    def save(self, *args, **kwargs):
        try:
            data = getaddress(self.lat, self.lon)
            self.address = data['formatted_address']
        except:
            pass
        super(Provider, self).save(*args, **kwargs)

    @staticmethod
    def nearby_providers(lat, lon, radius_km=5):
        """
        Find providers within specified radius (in kilometers)
        Returns queryset ordered by distance
        """
        # Haversine formula implementation in Django ORM
        earth_radius = 6371  # Earth's radius in kilometers

        return Provider.objects.annotate(
            distance=ExpressionWrapper(
                earth_radius * ACos(
                    Cos(Radians(float(lat))) * 
                    Cos(Radians(F('lat'))) * 
                    Cos(Radians(F('lon')) - Radians(float(lon))) + 
                    Sin(Radians(float(lat))) * 
                    Sin(Radians(F('lat')))
                ),
                output_field=FloatField()
            )
        ).filter(
            distance__lte=radius_km
        ).order_by('distance')
```


