Here's how you can dynamically generate choices for the `turn` field based on the related Service's counter:

```Python
class Service(models.Model):
    title = models.CharField(max_length=100)
    counter = models.PositiveIntegerField()

    def __str__(self) -> str:
        return f'{self.title}'

    def get_turn_choices(self):
        return [(i, str(i)) for i in range(1, self.counter + 1)]

class Reservation(models.Model):
    user = models.ForeignKey(User, on_delete=models.CASCADE)
    service = models.ForeignKey(Service, on_delete=models.CASCADE)
    turn = models.PositiveIntegerField()

    def __str__(self) -> str:
        return f'{self.user}'

    def clean(self):
        if self.service and self.turn:
            choices = self.service.get_turn_choices()
            if (self.turn, str(self.turn)) not in choices:
                raise ValidationError(f'Turn must be between 1 and {self.service.counter}')

    def save(self, *args, **kwargs):
        self.clean()
        super().save(*args, **kwargs)
```


