from django import forms

class ReservationForm(forms.ModelForm):
    class Meta:
        model = Reservation
        fields = ['user', 'service', 'turn']

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        if 'service' in self.data:
            try:
                service_id = int(self.data.get('service'))
                service = Service.objects.get(id=service_id)
                self.fields['turn'].widget = forms.Select(choices=service.get_turn_choices())
            except (ValueError, Service.DoesNotExist):
                pass
        elif self.instance.pk and self.instance.service:
            self.fields['turn'].widget = forms.Select(choices=self.instance.service.get_turn_choices())
